#include <bits/stdc++.h>
using namespace std;
int diff[10090],a[10090],b[10090];
int main()
{
    string s1,s2;
    cin>>s1>>s2;
    if(s1.size()<s2.size()||(s1.size()==s2.size()&&s1<s2))
    {
        cout<<"-";
        swap(s1,s2);
    }
    reverse(s1.begin(),s1.end());
    reverse(s2.begin(),s2.end());
    for(int i=0;i<=s1.size()-1;i++)
    {
        a[i]=s1[i]-48;
    }
    for(int i=0;i<=s2.size()-1;i++)
    {
        b[i]=s2[i]-48;
    }
    int len=s1.size()-1;
    for(int i=0;i<=len;i++)
    {
        if(a[i]-b[i]<0)
        {
            a[i]+=10;
            a[i+1]-=1;
        }
        diff[i]=a[i]-b[i];
    }
    while(diff[len]==0&&len>0)
    {
        len--;
    }
    for(int i=len;i>=0;i--)
    {
        cout<<diff[i];
    }
    return 0;
}
